import React, { useContext, useState } from 'react';

import ColoredNumberDisplay from '@appSharedComponents/ColoredNumberDisplay';
import Button from '@components/ui/Button';
import TextInput from '@components/ui/TextInput';

import { ToastNotificationContext } from '@providers/ToastNotification';
import { UserContext } from '@providers/User';
// import { AppDataIndexedDbContext } from '@appSharedProviders/AppIndexedDb';

import * as styles from './newTradePositionDialog.module.css';

/**
 * Component that displays the Trade Position entry / modify / exit dialaog
 * @param {Object} props Props passed to this component
 * @param {string} props.tradingsymbol Instrument trading symbol
 * @param {('NSE'|'BSE'|'NFO'|'CDS'|'MCX')} props.exchange Exchange where this instrument is listed / traded
 * @param {number} props.lotSize Lot size
 * @param {number} props.ltp LTP of the instrument
 * @param {number} props.closePrice Last day close price of instrument
 * @param {()=>{}} props.openNewOrAddToPosition Callback fn passed down by the positions component
 * @param {()=>{}} props.cancelOp Go back button. Takes user back to watchlist
 * @param {()=>{}} props.closeDialog Closes the bottom sheet
 */
export default function NewTradePositionDialog({ tradingsymbol, exchange, lotSize, ltp, closePrice, openNewOrAddToPosition, cancelOp, closeDialog }) {
	const [qty, setQty] = useState(/** @type {number} */ (lotSize));
	const [qtyErr, setQtyErr] = useState(/** @type {string} */ (''));
	const [isWip, setIsWip] = useState(/** @type {Boolean} */ (false));

	const { notify } = useContext(ToastNotificationContext);
	const { checkIfPlanActive } = useContext(UserContext);
	// const { setPosition } = useContext(AppDataIndexedDbContext);

	// function isMultipleOfLotSize(quantity, lotSize) {
	// 	if (quantity < lotSize)return false;	// Check if quantity is less than lotSize
	// 	return quantity % lotSize === 0;	// Check if quantity is a multiple of lotSize
	// }
	const _chkForQtyErrs = (qtyParam) => {
		// console.log('qtyParam:', qtyParam);
		// if (qtyParam === undefined) qtyParam = qty;	//read default value from state
		if (isNaN(Number(qtyParam))) return 'Quantity should be a number';
		if (!Number.isInteger(Number(qtyParam))) return 'Quantity should be an integer';
		if (qtyParam < lotSize) return 'Quantity cannot be less than lot-size';
		if (qtyParam % lotSize !== 0) return 'Quantity should be a multiple of lot-size';
		return '';
	};
	const validate_n_setQty = (e) => {
		setQtyErr(_chkForQtyErrs(Number(e.target.value)));
		setQty(Number(e.target.value));
	};

	/**
	 * Enter / update trade position in IndexedDB
	 * @returns {Promise<boolean>}
	 */
	const doBuy = async () => {
		const qtyErr = _chkForQtyErrs(qty);
		if (isWip) return false;
		if (qtyErr !== '') {
			notify(qtyErr, 'err');
			return false;
		}
		try {
			const isPlanActive = await checkIfPlanActive(); //this shall cause the 'PlaneExpiryGateway' component to not render this component and display plan expired dialog
			if (!isPlanActive) throw new Error('Plan Expired!');
			setIsWip(true);
			// const respFromBg = await browser.runtime.sendMessage({
			// 	action: 'position_enter',
			// 	userId: id,
			// 	tradingsymbol,
			// 	exchange,
			// 	entryPrice: ltp,
			// 	quantity: Number(qty),
			// 	direction: 'B', //B for BUY, S for SELL
			// });
			// if (!respFromBg || !Object.prototype.hasOwnProperty.call(respFromBg, 'status')) return false;
			// if (respFromBg.status === 'error') throw new Error(respFromBg.error);
			// if (respFromBg.status !== 'success') return false;
			// /** @type {import('@types_appShared').Position} */
			// const posData = {
			// 	sbl: tradingsymbol,
			// 	xh: exchange,
			// 	avg: ltp,
			// 	// sl: 0,
			// 	// tp: 0,
			// 	qty: Number(qty),
			// 	t: Date.now(),
			// 	// x: 'expiry datetime here',
			// 	dir: 'B', //direction === 'B' ? 'B' : 'S',
			// };
			// if (lotSize && !isNaN(lotSize) && Number(lotSize) > 1) {
			// 	posData.ltsz = Number(lotSize);
			// }
			const writtenPos = await openNewOrAddToPosition(tradingsymbol, exchange, ltp, Number(qty), Number(lotSize));
			if (!writtenPos) throw new Error('Failed to open or update position');

			//here update the state in positions component or provider
			notify('Trade position opened successfully', 'success');
			closeDialog();
			return true;
		} catch (err) {
			notify(err.message || 'Error opening or updating position', 'err');
			return false;
		} finally {
			setIsWip(false);
		}
	};

	// if(!ltp) return <div>Unable to read LTP for this instrument</div>
	return (
		<div className={styles.tradePositionMgmtC}>
			<div className={styles.posInfo}>
				<span>{tradingsymbol}</span>
				<ColoredNumberDisplay currentVal={ltp} baseVal={closePrice} />
			</div>
			<ul className={styles.posMetricsC}>
				<li>
					<TextInput type="number" title="Quantity" placeholder="Quantity" value={qty.toString()} onChange={validate_n_setQty} error={qtyErr} />
				</li>
			</ul>

			<div className={styles.posFtr}>
				<Button variant="tertiary" isDark={true} onClick={cancelOp}>
					Cancel
				</Button>
				<Button variant="buy" onClick={doBuy} isWip={isWip} wipText="Opening">
					BUY
				</Button>
			</div>
		</div>
	);
}
